from collections import deque, Counter
class Solution:
    def minOperationsQueries(self, n, edges, queries):
        adj = [[] for _ in range(n)]
        for u, v, w in edges:
            adj[u].append((v, w))
            adj[v].append((u, w))
        def bfs_path(a, b):
            prevn = {a: None}
            prevw = {}
            dq = deque([a])
            while dq:
                u = dq.popleft()
                if u == b:
                    break
                for v, w in adj[u]:
                    if v not in prevn:
                        prevn[v] = u
                        prevw[v] = w
                        dq.append(v)
            path_w = []
            cur = b
            while cur != a:
                path_w.append(prevw[cur])
                cur = prevn[cur]
            return path_w
        ans = []
        for a, b in queries:
            w = bfs_path(a, b)
            if not w:
                ans.append(0)
                continue
            c = Counter(w)
            ans.append(len(w) - max(c.values()))
        return ans

