from collections import deque
class Solution:
    def minOperationsQueries(self, n, edges, queries):
        adj = [[] for _ in range(n)]
        for u, v, w in edges:
            adj[u].append((v, w))
            adj[v].append((u, w))
        LOG = max(1, n.bit_length() + 1)
        parent = [[-1] * n for _ in range(LOG)]
        depth = [0] * n
        cnt = [[0] * 27 for _ in range(n)]
        visited = [False] * n
        visited[0] = True
        dq = deque([0])
        while dq:
            u = dq.popleft()
            for v, w in adj[u]:
                if not visited[v]:
                    visited[v] = True
                    parent[0][v] = u
                    depth[v] = depth[u] + 1
                    cnt[v] = cnt[u][:]
                    cnt[v][w] += 1
                    dq.append(v)
        for k in range(1, LOG):
            for v in range(n):
                p = parent[k - 1][v]
                parent[k][v] = parent[k - 1][p] if p != -1 else -1
        def lca(u, v):
            if depth[u] < depth[v]:
                u, v = v, u
            diff = depth[u] - depth[v]
            for k in range(LOG):
                if (diff >> k) & 1:
                    u = parent[k][u]
            if u == v:
                return u
            for k in range(LOG - 1, -1, -1):
                if parent[k][u] != -1 and parent[k][u] != parent[k][v]:
                    u = parent[k][u]
                    v = parent[k][v]
            return parent[0][u]
        ans = []
        for a, b in queries:
            l = lca(a, b)
            pathlen = depth[a] + depth[b] - 2 * depth[l]
            maxfreq = 0
            for w in range(1, 27):
                f = cnt[a][w] + cnt[b][w] - 2 * cnt[l][w]
                if f > maxfreq:
                    maxfreq = f
            ans.append(pathlen - maxfreq)
        return ans

