var minOperationsQueries = function(n, edges, queries) {
    const adj = Array.from({ length: n }, () => []);
    for (const [u, v, w] of edges) {
        adj[u].push([v, w]);
        adj[v].push([u, w]);
    }
    const LOG = Math.max(1, Math.floor(Math.log2(Math.max(n, 2))) + 2);
    const parent = Array.from({ length: LOG }, () => new Array(n).fill(-1));
    const depth = new Array(n).fill(0);
    const cnt = Array.from({ length: n }, () => new Array(27).fill(0));
    const visited = new Array(n).fill(false);
    visited[0] = true;
    const queue = [0];
    let qi = 0;
    while (qi < queue.length) {
        const u = queue[qi++];
        for (const [v, w] of adj[u]) {
            if (!visited[v]) {
                visited[v] = true;
                parent[0][v] = u;
                depth[v] = depth[u] + 1;
                cnt[v] = cnt[u].slice();
                cnt[v][w]++;
                queue.push(v);
            }
        }
    }
    for (let k = 1; k < LOG; k++) {
        for (let v = 0; v < n; v++) {
            const p = parent[k - 1][v];
            parent[k][v] = p !== -1 ? parent[k - 1][p] : -1;
        }
    }
    function lca(u, v) {
        if (depth[u] < depth[v]) { const t = u; u = v; v = t; }
        let diff = depth[u] - depth[v];
        for (let k = 0; k < LOG; k++) {
            if ((diff >> k) & 1) u = parent[k][u];
        }
        if (u === v) return u;
        for (let k = LOG - 1; k >= 0; k--) {
            if (parent[k][u] !== -1 && parent[k][u] !== parent[k][v]) {
                u = parent[k][u];
                v = parent[k][v];
            }
        }
        return parent[0][u];
    }
    const ans = [];
    for (const [a, b] of queries) {
        const l = lca(a, b);
        const pathlen = depth[a] + depth[b] - 2 * depth[l];
        let maxfreq = 0;
        for (let w = 1; w <= 26; w++) {
            const f = cnt[a][w] + cnt[b][w] - 2 * cnt[l][w];
            if (f > maxfreq) maxfreq = f;
        }
        ans.push(pathlen - maxfreq);
    }
    return ans;
};
